from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetAssetByNameNode(BaseNode):
    name = "Prism: Get Asset by Name"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("assets", "list")
        self.add_input("name", "string", widget_type="text", default="")
        self.add_output("asset", "dict")
        self.add_output("entity", "dict")
        self.add_output("matches", "list")
        self.add_output("found", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        name = (inputs.get("name") or "").strip()
        assets = list(inputs.get("assets") or [])
        if core is None:
            self.log_error("No PrismCore found.")
            return {"asset": {}, "entity": {}, "matches": [], "found": False}
        if not assets:
            try:
                assets = list(core.entities.getAssets() or [])
            except Exception as e:
                self.log_error(f"getAssets failed: {e}")
                return {"asset": {}, "entity": {}, "matches": [], "found": False}
        name_lower = name.lower()
        def leaf(a):
            p = a.get("asset_path", a.get("name", ""))
            return p.split("/")[-1].lower() if p else ""
        matches = [a for a in assets if not name or leaf(a) == name_lower]
        if not matches:
            self.log_error(f"Asset '{name}' not found in {len(assets)} asset(s).")
            return {"asset": {}, "entity": {}, "matches": [], "found": False}
        best = matches[0]
        entity = {"type": "asset", "asset_path": best.get("asset_path", best.get("name", ""))}
        self.log_info(f"Found {len(matches)} match(es) for '{name}'")
        return {"asset": best, "entity": entity, "matches": matches, "found": True}

def register_node():
    return PrismGetAssetByNameNode
